+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+struct StringMetrics {
+    scalar_count: usize,
+    utf16_units: usize,
+    has_non_bmp: bool,
+    is_ascii: bool,
+}
+
+fn inspect_string(value: &str) -> StringMetrics {
+    if value.is_ascii() {
+        let len = value.len();
+        return StringMetrics {
+            scalar_count: len,
+            utf16_units: len,
+            has_non_bmp: false,
+            is_ascii: true,
+        };
+    }
+
+    let mut scalar_count = 0;
+    let mut utf16_units = 0;
+    let mut has_non_bmp = false;
+    for ch in value.chars() {
+        scalar_count += 1;
+        if u32::from(ch) > 0xFFFF {
+            utf16_units += 2;
+            has_non_bmp = true;
+        } else {
+            utf16_units += 1;
+        }
+    }
+    StringMetrics {
+        scalar_count,
+        utf16_units,
+        has_non_bmp,
+        is_ascii: false,
+    }
+}
